function normalizePlatform(p) {
  const v = String(p || '').toLowerCase().trim();
  if (v === 'web') return 'website';
  return v || 'website';
}

function normalizeUrl(rawUrl) {
  let u = String(rawUrl || '').trim();
  if (!u) return null;

  if (!/^https?:\/\//i.test(u)) {
    u = 'https://' + u;
  }

  try {
    const parsed = new globalThis.URL(u);
    const host = parsed.hostname.replace(/^www\./i, '');
    return `${parsed.protocol}//${host}`;
  } catch {
    return u;
  }
}

const originalUrl = $json.url || null;
const normalizedUrl = normalizeUrl(originalUrl);

return {
  json: {
    ...$json,
    platform: normalizePlatform($json.platform),
    original_url: originalUrl,
    fetch_url: normalizedUrl,
    url: normalizedUrl
  }
};

function stripWww(host) {
  return String(host || '').replace(/^www\./i, '').toLowerCase();
}

function parseAbsoluteUrl(url) {
  const m = String(url || '').match(/^(https?):\/\/([^\/?#]+)(\/[^?#]*)?/i);
  if (!m) return null;

  return {
    protocol: m[1].toLowerCase(),
    host: stripWww(m[2]),
    path: m[3] || ''
  };
}

function normalizeUrl(url) {
  const parsed = parseAbsoluteUrl(url);
  if (!parsed) return null;

  const cleanPath = (parsed.path || '').replace(/\/$/, '');
  return `${parsed.protocol}://${parsed.host}${cleanPath}`;
}

function absolutize(baseUrl, href) {
  const base = parseAbsoluteUrl(baseUrl);
  if (!base) return null;

  const raw = String(href || '').trim();
  if (!raw) return null;

  if (/^https?:\/\//i.test(raw)) {
    return normalizeUrl(raw);
  }

  if (/^\/\//.test(raw)) {
    return normalizeUrl(`${base.protocol}:${raw}`);
  }

  if (/^\//.test(raw)) {
    return normalizeUrl(`${base.protocol}://${base.host}${raw}`);
  }

  if (/^[a-zA-Z][a-zA-Z0-9+.-]*:/.test(raw)) {
    return null;
  }

  const basePath = base.path || '';
  const dir = basePath.includes('/') ? basePath.replace(/\/[^\/]*$/, '/') : '/';
  return normalizeUrl(`${base.protocol}://${base.host}${dir}${raw}`);
}

function extractLinksFromHtml(html, baseUrl) {
  const out = [];
  const re = /<a\b[^>]*?\bhref\s*=\s*(?:"([^"]*)"|'([^']*)'|([^\s>]+))[^>]*>([\s\S]*?)<\/a>/gi;
  let m;

  while ((m = re.exec(String(html || ''))) !== null) {
    const rawHref = (m[1] || m[2] || m[3] || '').trim();
    const anchorHtml = m[4] || '';

    const anchorText = anchorHtml
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();

    const absolute = absolutize(baseUrl, rawHref);
    if (absolute) {
      out.push({
        href: absolute,
        anchor_text: anchorText
      });
    }
  }

  return out;
}

function extractLinksFromHeader(linkHeader, baseUrl) {
  const out = [];
  const text = String(linkHeader || '');
  if (!text) return out;

  const re = /<([^>]+)>/g;
  let m;

  while ((m = re.exec(text)) !== null) {
    const href = absolutize(baseUrl, m[1]);
    if (href) {
      out.push({
        href,
        anchor_text: 'header-link'
      });
    }
  }

  return out;
}

const items = $input.all();
const output = [];

for (const item of items) {
  const data = item.json;

  const html =
    typeof data.data === 'string'
      ? data.data
      : typeof data.body === 'string'
        ? data.body
        : data.data && typeof data.data.body === 'string'
          ? data.data.body
          : '';

  const baseUrl = data.fetch_url || data.url || null;
  const baseParsed = parseAbsoluteUrl(baseUrl);
  const seedHost = baseParsed ? baseParsed.host : null;

  if (!baseUrl || !seedHost || !html || html.length < 50) {
    continue;
  }

  const htmlLinks = extractLinksFromHtml(html, baseUrl);
  const headerLinks = extractLinksFromHeader(
    (data.headers && (data.headers.link || data.headers.Link)) || '',
    baseUrl
  );

  const dedup = new Map();

  for (const link of [...htmlLinks, ...headerLinks]) {
    const parsed = parseAbsoluteUrl(link.href);
    if (!parsed) continue;

    const normalized = normalizeUrl(link.href);
    if (!normalized) continue;

    if (!dedup.has(normalized)) {
      dedup.set(normalized, {
        href: normalized,
        host: parsed.host,
        anchor_text: link.anchor_text || null,
        same_domain: parsed.host === seedHost
      });
    }
  }

  for (const link of dedup.values()) {
    output.push({
      json: {
        seed_source_id: data.id,
        seed_source_name: data.name,
        seed_source_url: baseUrl,
        seed_trust_score: data.trust_score || 50,
        candidate_url: link.href,
        candidate_host: link.host,
        anchor_text: link.anchor_text,
        same_domain: link.same_domain
      }
    });
  }
}

return output;

function normalizeText(v) {
  return String(v || '').toLowerCase().trim();
}

function isAllowed(url, anchorText, sameDomain) {
  const u = normalizeText(url);
  const a = normalizeText(anchorText);
  const combined = `${u} ${a}`;

  const blocked = [
    'mailto:',
    'tel:',
    'javascript:',
    '/login',
    '/signin',
    '/signup',
    '/register',
    '/checkout',
    '/cart',
    '/warenkorb',
    '/privacy',
    '/datenschutz',
    '/impressum',
    '/agb',
    'facebook.com/sharer',
    'wa.me',
    'whatsapp',
    'linkedin.com/share'
  ];

  if (blocked.some(x => combined.includes(x))) return false;

  const interesting = /(veranstaltung|veranstaltungen|events?|termine|kalender|calendar|programm|kultur|festival|konzert|gemeinde|verein|jugend|frauen|cami|moschee|mosque|community|etkinlik|bilet|ticket)/i;
  if (!interesting.test(combined)) return false;

  if (!sameDomain) {
    const externalAllowed = /(verein|gemeinde|verband|jugend|frauen|kultur|moschee|cami|community)/i;
    if (!externalAllowed.test(combined)) return false;
  }

  return true;
}

const url = $json.candidate_url || null;
const anchorText = $json.anchor_text || '';
const sameDomain = !!$json.same_domain;

if (!url) {
  return {
    json: {
      ...$json,
      filtered_out: true,
      filter_reason: 'NO_URL'
    }
  };
}

if (!isAllowed(url, anchorText, sameDomain)) {
  return {
    json: {
      ...$json,
      filtered_out: true,
      filter_reason: 'NOT_ALLOWED'
    }
  };
}

return {
  json: {
    ...$json,
    filtered_out: false,
    filter_reason: null
  }
};

function scoreCandidate(url, anchorText, sameDomain, seedTrust) {
  const combined = `${url || ''} ${anchorText || ''}`.toLowerCase();
  let score = 0;

  if (sameDomain) score += 20;
  if (/veranstaltung|veranstaltungen|events?|termine|kalender|calendar/.test(combined)) score += 25;
  if (/programm|kultur|festival|konzert/.test(combined)) score += 20;
  if (/gemeinde|verein|verband|jugend|frauen|community|cami|moschee/.test(combined)) score += 20;
  if (/ticket|bilet/.test(combined)) score -= 10;
  if (/impressum|datenschutz|agb|privacy/.test(combined)) score -= 50;

  score += Math.floor((Number(seedTrust || 50) - 50) / 5);
  return Math.max(0, Math.min(100, score));
}

function inferName(url, anchorText) {
  const a = String(anchorText || '').trim();
  if (a.length >= 4 && a.length <= 120) return a;

  try {
    const parsed = new globalThis.URL(url);
    return parsed.hostname.replace(/^www\./i, '');
  } catch {
    return 'Discovered Source';
  }
}

if ($json.filtered_out) {
  return {
    json: {
      ...$json,
      candidate_name: null,
      candidate_platform: null,
      candidate_source_kind: null,
      candidate_trust_score: 0,
      discovery_method: null,
      dropped: true
    }
  };
}

const score = scoreCandidate(
  $json.candidate_url,
  $json.anchor_text,
  $json.same_domain,
  $json.seed_trust_score
);

const dropped = score < 40;

return {
  json: {
    ...$json,
    candidate_name: dropped ? null : inferName($json.candidate_url, $json.anchor_text),
    candidate_platform: dropped ? null : 'website',
    candidate_source_kind: dropped ? null : 'WEBSITE',
    candidate_trust_score: score,
    discovery_method: dropped ? null : 'source-discovery-v1',
    dropped
  }
};
